startingCSS:
.wrapper {
  background: #0f172a;
  padding: 2rem;
}

.card {
  max-width: 380px;
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 10px;
  padding: 1.5rem;
  color: #e2e8f0;
  /* Center this card horizontally */
}

.card strong {
  display: block;
  font-size: 1rem;
  margin-bottom: 0.5rem;
}

.card p {
  margin: 0;
  color: #94a3b8;
  font-size: 0.875rem;
  line-height: 1.5;
}

alternatives.css:
.section {
  padding-block: 3rem; /* top and bottom */
  padding-inline: 1.5rem; /* left and right */
}
